  text: JSON.stringify({
    reflection: 'Today\'s theme of Stability calls us to ground ourselves in God\'s unchanging love, just as Paul showed stability in his ministry to the Thessalonians.',
    challenge: 'Practice lectio divina with today\'s first reading. Stay present in prayer without rushing.',
    prayer: 'Lord, like Paul who remained steadfast in his mission, help us find stability in you. Guide us to be authentic witnesses of your love. Amen.',
    historicalFacts: [
      {year: '1920', fact: 'The 19th Amendment granting women the right to vote was certified.'},
      {year: '1978', fact: 'Pope John Paul I was installed as Pope.'}
    ]
  })
};

console.log('AI returning:', JSON.stringify(aiResponse, null, 2));
return aiResponse;

// Debug what Email Compiler gets
const aiData = $json; // This is the AI response
const allInputs = $input.all(); // This should have the workflow data

console.log('=== EMAIL COMPILER DEBUG ===');
console.log('AI data:', JSON.stringify(aiData, null, 2));
console.log('Number of inputs:', allInputs.length);
console.log('All inputs:', JSON.stringify(allInputs, null, 2));

if (allInputs.length > 0) {
  const workflowData = allInputs[0]?.json || {};
  console.log('❓ Workflow data keys:', Object.keys(workflowData));
  console.log('❓ Has readings:', !!workflowData.readings);

  if (workflowData.readings) {
    console.log('✅ Found readings:', workflowData.readings.firstReading);
  } else {
    console.log('❌ No readings found in workflow data');
  }
} else {
  console.log('❌ No inputs available to Email Compiler');
}

return {
  aiDataExists: !!aiData,
  inputsCount: allInputs.length,
  hasWorkflowData: allInputs.length > 0,
  hasReadings: allInputs.length > 0 && !!allInputs[0]?.json?.readings
};
